<script setup lang="ts">
import { ref } from 'vue'
import { api, APIError } from '@/api/client'
const characterName = ref(''); const password = ref(''); const confirmPassword = ref(''); const busy = ref(false); const error = ref<string|null>(null); const submittedName = ref<string|null>(null)
async function submit() { error.value = null; if (password.value !== confirmPassword.value) { error.value = '两次输入的密码不一致。'; return }; busy.value = true; try { const result = await api.auth.register(characterName.value, password.value, confirmPassword.value); submittedName.value = result.characterName; password.value = ''; confirmPassword.value = '' } catch(value) { const messages:Record<string,string>={player_not_online:'未找到该在线角色，请确认角色名完全一致，并保持角色在线。',player_name_ambiguous:'当前有多个同名在线角色，无法安全关联，请联系管理员。',player_identity_unavailable:'已找到角色，但无法确认对应的 Steam 身份，请联系管理员。',palworld_unavailable:'Palworld API 暂时不可用，未创建申请。',duplicate_account:'该游戏角色已经存在账号或申请。'}; error.value = value instanceof APIError ? messages[value.code] ?? value.message : '申请失败，请重试。' } finally { busy.value = false } }
</script>
<template><div class="simple-page auth-page"><p class="eyebrow">PLAYER APPLICATION</p><h1>申请玩家账号</h1><section class="section-block prose-card"><div v-if="submittedName" class="notice success">已为角色「{{ submittedName }}」提交申请。<br>管理员批准后可使用角色名和密码登录。</div><form v-else class="auth-form" @submit.prevent="submit"><p><strong>请先进入本 Palworld 服务器并保持在线。</strong><br>填写游戏内角色名后，服务器会从当前在线角色中自动关联账号。申请仍需管理员批准。</p><label>角色名<input v-model="characterName" autocomplete="nickname" maxlength="80" required /></label><label>密码<input v-model="password" type="password" autocomplete="new-password" minlength="8" maxlength="128" required /></label><label>确认密码<input v-model="confirmPassword" type="password" autocomplete="new-password" minlength="8" maxlength="128" required /></label><div v-if="error" class="notice danger">{{ error }}</div><button class="primary-button" :disabled="busy">{{ busy ? '正在核对在线角色…' : '提交申请' }}</button></form><RouterLink class="text-link" to="/login">返回登录 →</RouterLink></section></div></template>
